    public static ArrayList<Token> listaErrores = new ArrayList<>();
    public static AnalizadorSemantico semantico  = new AnalizadorSemantico();

    @Override
    public void syntax_error(Symbol s) {
        String lexema = s.value != null ? s.value.toString() : "EOF";
        String msg;

        if (s.sym == sym.EOF) {
            msg = "Fin de archivo inesperado — verifique que todos los bloques " +
                  "{ } [ ] estén cerrados correctamente";
        } else {
            switch (s.sym) {
                case sym.PUNTOCOMA:       msg = "Se esperaba ';'"; break;
                case sym.CORCHETE_CIERRA: msg = "Se esperaba ']'"; break;
                case sym.CORCHETE_ABRE:   msg = "Se esperaba '['"; break;
                case sym.LLAVE_CIERRA:    msg = "Se esperaba '}'"; break;
                case sym.LLAVE_ABRE:      msg = "Se esperaba '{'"; break;
                case sym.COMA:            msg = "Se esperaba ','"; break;
                case sym.PARENTESIS_CIERRA: msg = "Se esperaba ')'"; break;
                case sym.PARENTESIS_ABRE:   msg = "Se esperaba '('"; break;
                case sym.DOSPUNTOS:         msg = "Se esperaba ':'"; break;
                default:
                    msg = "Token inesperado '" + lexema + "' " +
                          "(código: " + s.sym + ") en línea " + (s.left+1);
            }
        }
        listaErrores.add(new Token(lexema, s.left+1, s.right+1, "Sintáctico", msg));
    }

    @Override
    public void report_error(String message, Object info) {
        if (info instanceof Symbol) {
            Symbol sym = (Symbol) info;
            listaErrores.add(new Token(
                sym.value != null ? sym.value.toString() : "EOF",
                sym.left+1, sym.right+1, "Sintáctico", message
            ));
        }
    }

    @Override
    public void report_fatal_error(String message, Object info) {
        report_error(message, info);
    }

    /* ── Detecta si un valor contiene comodín ── */
    public static boolean contieneComodin(Object value) {
        if (value == null) return false;

        if (value instanceof String) {
            String s = (String) value;
            // Buscar cualquier "?" en el string
            if (s.contains("?")) return true;

            // También verificar patrones con comodines
            if (s.matches("[\\d.]+[+\\-*/%^]\\?")) return true;
            if (s.matches("\\?[+\\-*/%^][\\d.]+")) return true;
        }

        // Verificar si es una lista que contiene comodines
        if (value instanceof List) {
            List<?> list = (List<?>) value;
            for (Object item : list) {
                if (contieneComodin(item)) return true;
            }
        }

        return false;
    }

     public static Object evaluarArgumento(Object arg) {
            if (arg == null) return null;

            System.out.println("[evaluarArgumento] Recibido: " + arg +
                             " (tipo: " + arg.getClass().getSimpleName() + ")");

            // Si es una expresión que necesita evaluación
            if (arg instanceof String) {
                String str = (String) arg;

                // Si es una expresión aritmética con operadores
                if (str.matches(".*[+\\-*/%^].*") && !str.contains("?")) {
                    try {
                        double result = semantico.evaluar(str);
                        System.out.println("[evaluarArgumento] Expresión evaluada: " + str + " = " + result);
                        return result;
                    } catch (Exception e) {
                        System.out.println("[evaluarArgumento] Error evaluando expresión: " + e.getMessage());
                    }
                }

                // Si es un número en string
                try {
                    double num = Double.parseDouble(str);
                    return num;
                } catch (NumberFormatException e) {
                    // No es número, devolver el string
                }
            }

            // Si es número, devolver directamente
            if (arg instanceof Number) {
                return arg;
            }

            return arg;
        }


